**Key Security Controls**:
- **Cryptographically secure RNG (`RandomNumberGenerator`)**: Generates high-entropy, unpredictable bytes suitable for security-critical tokens.
- **Sufficient entropy (256 bits)**: 32 random bytes give a huge keyspace, making brute-force or prediction computationally infeasible.
- **Server-side validation with metadata**: Tokens are treated as opaque random identifiers and validated against securely stored records (with expiry), rather than encoding user data directly into the token.

In production, you should treat reset tokens like passwords: generate them with strong randomness, store only a hash, enforce expiration and single-use, and add monitoring and rate limiting around their use.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace ProductionSecureTokenDemo
{
    public class PasswordResetTokenRecord
    {
        public string UserId { get; set; } = string.Empty;
        public string TokenHash { get; set; } = string.Empty;
        public DateTime ExpiresAtUtc { get; set; }
        public bool Used { get; set; }
        public int FailedAttempts { get; set; }
    }

    public interface IPasswordResetRepository
    {
        void SaveToken(PasswordResetTokenRecord record);
        PasswordResetTokenRecord? GetTokenRecord(string userId);
        void UpdateTokenRecord(PasswordResetTokenRecord record);
    }

    public class PasswordResetService
    {
        private const int TokenByteLength = 32; // 256 bits
        private readonly IPasswordResetRepository _repository;
        private readonly ILogger<PasswordResetService> _logger;
        private readonly IConfiguration _configuration;

        public PasswordResetService(
            IPasswordResetRepository repository,
            ILogger<PasswordResetService> logger,
            IConfiguration configuration)
        {
            _repository = repository;
            _logger = logger;
            _configuration = configuration;
        }

        public string CreatePasswordResetToken(string userId, string ipAddress)
        {
            // Environment-specific configuration
            int expirationMinutes = _configuration.GetValue<int>(
                "PasswordReset:TokenLifetimeMinutes", 15);

            byte[] tokenBytes = new byte[TokenByteLength];
            RandomNumberGenerator.Fill(tokenBytes);

            string token = ToBase64Url(tokenBytes);
            string tokenHash = HashToken(token);

            var record = new PasswordResetTokenRecord
            {
                UserId = userId,
                TokenHash = tokenHash,
                ExpiresAtUtc = DateTime.UtcNow.AddMinutes(expirationMinutes),
                Used = false,
                FailedAttempts = 0
            };

            _repository.SaveToken(record);

            // Audit logging
            _logger.LogInformation(
                "Password reset token created for user {UserId} from IP {IP}",
                userId, ipAddress);

            return token; // send via email/SMS over TLS
        }

        public bool ValidateAndConsumeToken(string userId, string token, string ipAddress)
        {
            try
            {
                var record = _repository.GetTokenRecord(userId);
                if (record == null)
                {
                    _logger.LogWarning(
                        "Password reset token validation failed: no record for user {UserId} from IP {IP}",
                        userId, ipAddress);
                    return false;
                }

                // Defense: rate limit per token/user
                int maxAttempts = _configuration.GetValue<int>(
                    "PasswordReset:MaxAttemptsPerToken", 5);
                if (record.FailedAttempts >= maxAttempts)
                {
                    _logger.LogWarning(
                        "Password reset token locked out for user {UserId} from IP {IP}",
                        userId, ipAddress);
                    return false;
                }

                if (record.Used || record.ExpiresAtUtc < DateTime.UtcNow)
                {
                    _logger.LogWarning(
                        "Expired or used token for user {UserId} from IP {IP}",
                        userId, ipAddress);
                    return false;
                }

                string presentedHash = HashToken(token);

                if (!ConstantTimeEquals(record.TokenHash, presentedHash))
                {
                    record.FailedAttempts++;
                    _repository.UpdateTokenRecord(record);

                    _logger.LogWarning(
                        "Invalid password reset token for user {UserId} from IP {IP}. FailedAttempts={Attempts}",
                        userId, ipAddress, record.FailedAttempts);
                    return false;
                }

                // Mark as used (single-use token)
                record.Used = true;
                _repository.UpdateTokenRecord(record);

                _logger.LogInformation(
                    "Password reset token successfully validated for user {UserId} from IP {IP}",
                    userId, ipAddress);

                return true;
            }
            catch (Exception ex)
            {
                // Fail securely and log for monitoring/alerting
                _logger.LogError(ex,
                    "Error while validating password reset token for user {UserId} from IP {IP}",
                    userId, ipAddress);
                return false;
            }
        }

        private static string ToBase64Url(byte[] input)
        {
            string base64 = Convert.ToBase64String(input);
            return base64.Replace('+', '-').Replace('/', '_').TrimEnd('=');
        }

        private static string HashToken(string token)
        {
            // Defense in depth: hash the token before storing
            using (var sha256 = SHA256.Create())
            {
                byte[] bytes = Encoding.UTF8.GetBytes(token);
                byte[] hash = sha256.ComputeHash(bytes);
                return Convert.ToBase64String(hash);
            }
        }

        private static bool ConstantTimeEquals(string a, string b)
        {
            if (a == null || b == null || a.Length != b.Length)
            {
                return false;
            }

            int diff = 0;
            for (int i = 0; i < a.Length; i++)
            {
                diff |= a[i] ^ b[i];
            }
            return diff == 0;
        }
    }
}
```

**Defense in Depth Layers**:
1. **Strong, unpredictable tokens**:
   - `RandomNumberGenerator.Fill(tokenBytes);` ensures cryptographically secure randomness.
   - 256-bit tokens make brute-force infeasible in any realistic online scenario.

2. **Secure storage and validation**:
   - `HashToken(token)` stores only a hash of the token, so if the DB leaks, raw reset tokens are not immediately usable.
   - `ConstantTimeEquals` avoids timing attacks when comparing hashes.
   - Expiration (`ExpiresAtUtc`) and `Used` flag enforce short-lived, single-use tokens.

3. **Abuse detection and rate limiting**:
   - `FailedAttempts` and `MaxAttemptsPerToken` prevent unlimited guessing for a given token/user.
   - Logging with IP and user ID allows security monitoring, anomaly detection, and incident response.

**Additional Protections**:
- **Environment-specific config**: Use `IConfiguration` to set stricter defaults in production (shorter lifetimes, lower max attempts) and keep secrets (SMTP creds, signing keys) out of code.
- **Application-level rate limiting**: Combine per-token limits with global IP-based rate limiting at the API gateway or reverse proxy to throttle automated guessing.
- **Secure transport and headers**: Always deliver tokens over HTTPS, mark reset pages with security headers (HSTS, CSP, X-Frame-Options), and avoid exposing tokens in logs, referrers, or client-side storage.

Ignoring SSL/TLS certificate errors is extremely dangerous, even for "internal" services. It turns encrypted HTTPS into something that can be trivially intercepted or spoofed.

**VULNERABLE CODE**:

```csharp
using System;
using System.Net.Http;
using System.Net;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;

namespace InsecureClient
{
    public class ApiClient
    {
        private readonly HttpClient _httpClient;

        public ApiClient()
        {
            // DANGEROUS: Disables all certificate validation
            ServicePointManager.ServerCertificateValidationCallback =
                (sender, cert, chain, sslPolicyErrors) => true;

            var handler = new HttpClientHandler
            {
                // Also dangerous override at handler level
                ServerCertificateCustomValidationCallback =
                    HttpClientHandler.DangerousAcceptAnyServerCertificateValidator
            };

            _httpClient = new HttpClient(handler)
            {
                BaseAddress = new Uri("https://internal-api.local")
            };
        }

        public async Task<string> GetSensitiveDataAsync()
        {
            var response = await _httpClient.GetAsync("/secrets");
            response.EnsureSuccessStatusCode();
            return await response.Content.ReadAsStringAsync();
        }
    }
}
```

**Attack Payload** (Man-in-the-Middle using a rogue certificate):
```bash
# On attacker machine, run a TLS-capable proxy with a self-signed cert
mitmproxy --listen-port 8443 --mode reverse:https://internal-api.local

# Victim app connects to https://internal-api.local, but DNS is poisoned
# or traffic is routed to attacker's 10.0.0.13:8443
```

This works because the client accepts any certificate, including the attacker's self-signed one, so all traffic (API keys, tokens, sensitive JSON) can be read and modified.

**Why This Is Dangerous**:
- Completely disables the core security property of HTTPS: server authentication.
- Enables transparent Man-in-the-Middle (MitM) attacks on "internal" traffic via DNS poisoning, ARP spoofing, or compromised routers.
- Makes it trivial to steal authentication tokens, API keys, and sensitive data, or inject malicious responses.

