**Key Security Controls**:
- **Strict TLS validation**: Uses `ServerCertificateCustomValidationCallback` to enforce that the certificate chain is valid and trusted by the OS, rather than blindly accepting any certificate.
- **Certificate pinning**: Optionally validates the server certificate thumbprint against a known-good value, mitigating risks from compromised CAs or mis-issued certificates.
- **Secure error handling and logging**: Fails closed (request fails if validation fails), logs diagnostic information without exposing secrets, and avoids falling back to insecure behavior.

In production microservices, you need a scalable pattern that supports certificate rotation, mutual TLS, and centralized configuration, without ever disabling validation.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Concurrent;
using System.Net.Http;
using System.Net.Security;
using System.Security.Authentication;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;

namespace SecureMicroservices
{
    public sealed class CertificatePin
    {
        public string ServiceName { get; init; } = string.Empty;
        public string AllowedThumbprint { get; init; } = string.Empty; // Normalized
    }

    public interface ICertificatePinStore
    {
        CertificatePin? GetPin(string serviceName);
    }

    // Example in-memory store; in production use configuration service / secrets manager
    public class InMemoryCertificatePinStore : ICertificatePinStore
    {
        private readonly ConcurrentDictionary<string, CertificatePin> _pins = new();

        public InMemoryCertificatePinStore()
        {
            // Loaded from secure configuration (KeyVault, AWS Secrets Manager, etc.)
            _pins["user-service"] = new CertificatePin
            {
                ServiceName = "user-service",
                AllowedThumbprint = "ABCD1234EF567890ABCD1234EF567890ABCD1234"
            };
        }

        public CertificatePin? GetPin(string serviceName)
        {
            _pins.TryGetValue(serviceName, out var pin);
            return pin;
        }
    }

    public class SecureHttpClientFactory
    {
        private readonly ICertificatePinStore _pinStore;

        public SecureHttpClientFactory(ICertificatePinStore pinStore)
        {
            _pinStore = pinStore;
        }

        public HttpClient CreateClient(string serviceName, string baseUrl)
        {
            var handler = new HttpClientHandler
            {
                SslProtocols = SslProtocols.Tls12 | SslProtocols.Tls13,
                ServerCertificateCustomValidationCallback = (request, cert, chain, errors) =>
                    ValidateServerCertificate(serviceName, request, cert, chain, errors)
            };

            var client = new HttpClient(handler)
            {
                BaseAddress = new Uri(baseUrl, UriKind.Absolute),
                Timeout = TimeSpan.FromSeconds(5)
            };

            return client;
        }

        private bool ValidateServerCertificate(
            string serviceName,
            HttpRequestMessage request,
            X509Certificate2? cert,
            X509Chain? chain,
            SslPolicyErrors sslPolicyErrors)
        {
            // Layer 1: Require standard OS-level validation
            if (sslPolicyErrors != SslPolicyErrors.None || cert == null)
            {
                LogValidationFailure(serviceName, request, sslPolicyErrors, "Chain validation failed");
                return false;
            }

            // Layer 2: Optional pinning per service (rotate pins via config when certs rotate)
            var pin = _pinStore.GetPin(serviceName);
            if (pin != null)
            {
                string thumbprint = cert.Thumbprint?
                    .Replace(" ", string.Empty, StringComparison.Ordinal)
                    .ToUpperInvariant() ?? string.Empty;

                if (!string.Equals(thumbprint, pin.AllowedThumbprint, StringComparison.Ordinal))
                {
                    LogValidationFailure(serviceName, request, sslPolicyErrors, "Thumbprint mismatch");
                    return false;
                }
            }

            return true;
        }

        private void LogValidationFailure(
            string serviceName,
            HttpRequestMessage request,
            SslPolicyErrors errors,
            string reason)
        {
            // Logging & monitoring hook (wire into Serilog, AppInsights, etc.)
            Console.Error.WriteLine(
                $"[TLS-VALIDATION-FAIL] Service={serviceName} Url={request.RequestUri} " +
                $"Errors={errors} Reason={reason}");
        }
    }

    public class UserServiceClient
    {
        private readonly HttpClient _client;

        public UserServiceClient(SecureHttpClientFactory factory)
        {
            // In prod, base URL & service name from config per environment
            _client = factory.CreateClient("user-service", "https://user-service.prod.svc.cluster.local");
        }

        public async Task<string> GetUserProfileAsync(string userId)
        {
            try
            {
                using var response = await _client.GetAsync($"/api/users/{Uri.EscapeDataString(userId)}");
                if (!response.IsSuccessStatusCode)
                {
                    // Graceful degradation & logging
                    Console.Error.WriteLine(
                        $"[WARN] user-service returned {response.StatusCode} for {userId}");
                    return string.Empty; // or fallback behavior
                }

                return await response.Content.ReadAsStringAsync();
            }
            catch (HttpRequestException ex)
            {
                Console.Error.WriteLine(
                    $"[ERROR] user-service request failed: {ex.Message}");
                // Optionally trigger alerting here
                return string.Empty;
            }
        }
    }
}
```

**Defense in Depth Layers**:
1. **OS-level TLS validation**: 
   - Code: `if (sslPolicyErrors != SslPolicyErrors.None || cert == null) return false;`
   - Relies on the platform trust store, proper hostname verification, and full chain validation. Never bypass this.
2. **Config-driven certificate pinning**:
   - Code: `ICertificatePinStore` with per-service thumbprints, loaded from secure configuration.
   - Allows controlled certificate rotation: update pins ahead of rotation in all environments; support multiple pins during a migration window if needed.
3. **Logging, monitoring, and graceful failure**:
   - Code: `LogValidationFailure(...)` and structured error logging in `GetUserProfileAsync`.
   - Provides audit trails for failed TLS handshakes and allows alerting on spikes in validation failures that may indicate MitM attempts or misconfiguration.

**Additional Protections**:
- **Environment-specific configuration**: Use different base URLs, pins, and possibly separate CAs for dev, staging, and prod. Load all sensitive config (thumbprints, client certs) from a secret manager, not code.
- **Mutual TLS (mTLS)**: For sensitive internal APIs, configure `HttpClientHandler.ClientCertificates` with a client cert and require client certs on the server. This authenticates both sides and isolates traffic between services.
- **Rate limiting and circuit breaking**: Combine with a resilience library (e.g., Polly) to add retry policies, rate limiting, and circuit breakers so that certificate issues or upstream failures don't cascade; always fail closed, never fallback to `DangerousAcceptAnyServerCertificateValidator`.

