This isn't a traditional input payload; the "payload" is the fact that your secrets are statically embedded. Any leak of the source, config, or logs hands over real credentials to the attacker.

**Why This Is Dangerous**:
- Secrets are stored in plaintext and can be extracted from source control, backups, or CI logs.
- Rotation is painful and often skipped; the same keys stay valid for months or years.
- A single repo compromise enables lateral movement into databases, payment providers, and other critical systems.

**SECURE VERSION**:

Below is a more secure pattern using environment variables and (optionally) Azure Key Vault. It also enforces encryption and least privilege.

```csharp
using System;
using System.Data.SqlClient;
using Azure.Identity;
using Azure.Security.KeyVault.Secrets;

namespace MySecureApp
{
    public class SecureApiClient
    {
        // Environment variable names (no secrets here)
        private const string ApiKeyEnv = "PAYMENT_API_KEY_SECRET_NAME";
        private const string KeyVaultUrlEnv = "KEYVAULT_URL";
        private const string DbConnectionEnv = "DB_CONNECTION_STRING";

        private readonly string _apiKey;
        private readonly string _dbConnectionString;

        public SecureApiClient()
        {
            // PRIMARY: Load from secret store / env, not from code
            var keyVaultUrl = Environment.GetEnvironmentVariable(KeyVaultUrlEnv);
            if (!string.IsNullOrWhiteSpace(keyVaultUrl))
            {
                // Use managed identity / DefaultAzureCredential in production
                var client = new SecretClient(new Uri(keyVaultUrl), new DefaultAzureCredential());

                var apiKeySecretName = Environment.GetEnvironmentVariable(ApiKeyEnv) ?? "payment-api-key";
                try
                {
                    KeyVaultSecret apiKeySecret = client.GetSecret(apiKeySecretName);
                    _apiKey = apiKeySecret.Value;
                }
                catch (Exception ex)
                {
                    Console.Error.WriteLine($"[ERROR] Failed to load API key from Key Vault: {ex.Message}");
                    throw new InvalidOperationException("Unable to load API key", ex);
                }
            }
            else
            {
                // Fallback: environment variable (still better than hard-coding)
                _apiKey = Environment.GetEnvironmentVariable("PAYMENT_API_KEY")
                    ?? throw new InvalidOperationException("PAYMENT_API_KEY is not configured.");
            }

            // Database connection string from environment or secret store
            _dbConnectionString = Environment.GetEnvironmentVariable(DbConnectionEnv)
                ?? throw new InvalidOperationException("DB_CONNECTION_STRING is not configured.");

            // Enforce encryption in transit
            if (_dbConnectionString.Contains("Encrypt=False", StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Database connection must use Encrypt=True.");
            }
        }

        public void CallPaymentProvider(decimal amount, string currency)
        {
            if (amount <= 0)
            {
                throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");
            }

            // Use _apiKey securely in HTTP headers (not logged!)
            Console.WriteLine($"Calling payment API for {amount} {currency}.");
            // Do NOT log _apiKey
        }

        public void StorePaymentRecord(string reference, decimal amount)
        {
            try
            {
                using (var connection = new SqlConnection(_dbConnectionString))
                {
                    connection.Open();
                    using (var cmd = connection.CreateCommand())
                    {
                        cmd.CommandText =
                            "INSERT INTO Payments(Reference, Amount, CreatedAtUtc) VALUES(@ref, @amt, SYSUTCDATETIME())";
                        cmd.Parameters.AddWithValue("@ref", reference);
                        cmd.Parameters.AddWithValue("@amt", amount);
                        cmd.ExecuteNonQuery();
                    }
                }
            }
            catch (SqlException ex)
            {
                // Log minimal, non-sensitive info
                Console.Error.WriteLine($"[ERROR] Database operation failed: {ex.Number}");
                throw; // Bubble up or map to a safe error in higher layers
            }
        }

        public static void Main(string[] args)
        {
            try
            {
                var client = new SecureApiClient();
                client.CallPaymentProvider(100.0m, "USD");
                client.StorePaymentRecord("INV-123", 100.0m);
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"[FATAL] Application startup failed: {ex.Message}");
            }
        }
    }
}
```

**Key Security Controls**:
- **Secrets externalized and centralized**: Secrets are loaded from environment variables or a secret manager (Azure Key Vault), not from source code, reducing exposure in repos and backups.
- **Secure transport and configuration validation**: The code enforces encrypted DB connections and validates configuration at startup, failing fast if secrets are missing or misconfigured.
- **Safe logging and error handling**: Errors log only non-sensitive metadata (e.g., SQL error number), avoiding accidental secret leakage into logs or monitoring systems.

In production, you want layered defenses: centralized secret management, short-lived credentials, environment-specific configuration, strict logging practices, and monitoring for misuse. Below is an example of an ASP.NET Core pattern that integrates Azure Key Vault, environment isolation, rotation, and observability.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Net.Http;
using System.Threading;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.Security.KeyVault.Secrets;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

namespace ProductionSecureApp
{
    public class PaymentOptions
    {
        public string ApiBaseUrl { get; set; } = string.Empty;
        public string ApiKeySecretName { get; set; } = "payment-api-key";
        public int TimeoutSeconds { get; set; } = 10;
    }

    public interface IPaymentClient
    {
        Task<bool> ChargeAsync(decimal amount, string currency, CancellationToken ct = default);
    }

    public class PaymentClient : IPaymentClient
    {
        private readonly HttpClient _httpClient;
        private readonly SecretClient _secretClient;
        private readonly PaymentOptions _options;
        private readonly ILogger<PaymentClient> _logger;

        public PaymentClient(HttpClient httpClient,
                             SecretClient secretClient,
                             PaymentOptions options,
                             ILogger<PaymentClient> logger)
        {
            _httpClient = httpClient;
            _secretClient = secretClient;
            _options = options;
            _logger = logger;
        }

        private async Task<string> GetApiKeyAsync(CancellationToken ct)
        {
            try
            {
                KeyVaultSecret secret = await _secretClient
                    .GetSecretAsync(_options.ApiKeySecretName, cancellationToken: ct);
                return secret.Value;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to retrieve payment API key from Key Vault");
                throw new InvalidOperationException("Payment API key unavailable.", ex);
            }
        }

        public async Task<bool> ChargeAsync(decimal amount, string currency, CancellationToken ct = default)
        {
            if (amount <= 0) throw new ArgumentOutOfRangeException(nameof(amount));

            string apiKey = await GetApiKeyAsync(ct);

            using var request = new HttpRequestMessage(HttpMethod.Post, "charges");
            request.Headers.Add("X-API-Key", apiKey); // never log this
            request.Content = new StringContent($"{{\"amount\":{amount},\"currency\":\"{currency}\"}}");

            try
            {
                var response = await _httpClient.SendAsync(request, ct);
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogWarning("Payment API returned non-success status {StatusCode}",
                        (int)response.StatusCode);
                    return false;
                }

                return true;
            }
            catch (TaskCanceledException ex)
            {
                _logger.LogError(ex, "Payment request timed out");
                return false; // Graceful degradation
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error calling payment API");
                return false;
            }
        }
    }

